//---------------------------------------------------------------------------------------------

// #DRA:
//
// NOTES:
//
// The FDCAN calculates the Tx FIFO free level FDCAN_TXFQS.TFFL as difference between get and
// put index. New transmit messages have to be written to the Tx FIFO starting with the Tx
// buffer referenced by the put index FDCAN_TXFQS.TFQPI.
//
// FDCAN Tx FIFO/queue status register (FDCAN_TXFQS)
// The Tx FIFO/queue status is related to the pending Tx requests listed in register
// FDCAN_TXBRP. Therefore the effect of add/cancellation requests may be delayed due to a
// running Tx scan (FDCAN_TXBRP not yet updated).
//
// IMPORTANT:
//
// 1. When a single message is added to the Tx FIFO, the transmission is requested by writing a
// 1 to the FDCAN_TXBAR bit related to the Tx buffer referenced by the Tx FIFO put index.
//
// 2. When multiple (n) messages are added to the Tx FIFO, they are written to n consecutive Tx
// buffers starting with the put index. The transmissions are then requested via
// FDCAN_TXBAR. The put index is then cyclically incremented by n. The number of
// requested Tx buffers should not exceed the number of free Tx buffers as indicated by the Tx
// FIFO free level.
//

#  if defined(dAddMultipleTxCANMessagesToFIFO)

//
//- - - - - - - - CRC_Evans_CheckTxFifoLevel - - - - - - -
//
uint32_t CRC_Evans_CheckTxFifoLevel(FDCAN_HandleTypeDef* hfdcan, uint32_t * pu32FreeLevel, bool * pErrorAbortTx, toN_ErrorsAndErrorStatuses * poN_ErrorsAndErrorStatuses)
{
	int iRetries = 0;
	uint32_t u32FDCAN_IR_Flags = 0;
	/* Get number of consecutive free Tx FIFO elements starting from Tx FIFO GetIndex. */
	/* Free Level is the number of FIFOs that are available to receive the Tx CAN Frames. */
	while (0 == ((*pu32FreeLevel) = HAL_FDCAN_GetTxFifoFreeLevel(hfdcan)))
	{
		if ((dCANRetryCounts == iRetries) && (false == (*pErrorAbortTx)))
		{
			assert_failed((uint8_t*)__FILE__, __LINE__);
			break;
		}
		else if ((false == (*pErrorAbortTx)) && (0 != (hfdcan->Instance->IR & (FDCAN_ERROR_FLAGS))))
		{
			u32FDCAN_IR_Flags = poN_ErrorsAndErrorStatuses->u32CurrentFDCAN_IR_Value | (hfdcan->Instance->IR & (FDCAN_ERROR_FLAGS));
			break;
		}
		else if (true == (*pErrorAbortTx))
		{
			u32FDCAN_IR_Flags = poN_ErrorsAndErrorStatuses->u32CurrentFDCAN_IR_Value;
			break;
		}
		else
		{
			HAL_Delay(1);
		}
		iRetries++;
	}
	return u32FDCAN_IR_Flags;
}


//
//- - - - - - - - CRC_Evans_FDCAN_AddMultipleMessagesToTxFifoQ - - - - - - -
//
CRC_StatusTypeDef CRC_Evans_FDCAN_AddMultipleMessagesToTxFifoQ(FDCAN_HandleTypeDef* hfdcan, uint32_t u32NumberOfMessagesToAddToTxFIFO, FDCAN_TxHeaderTypeDef* pTxHeader, uint8_t* pTxData)
{
	bool* pErrorAbortTx = NULL;
	toN_ErrorsAndErrorStatuses* poN_ErrorsAndErrorStatuses = NULL;
	CRC_StatusTypeDef nStatus;
	uint32_t u32FDCAN_IR_Flags = 0;
	uint32_t u32FreeLevel = 0;

	switch((uint32_t)hfdcan->Instance)
	{
		default:
		{
			assert_failed((uint8_t *)__FILE__, __LINE__);
			break;
		}

#   if (1 == MX_FDCAN1)

		case (uint32_t)(FDCAN1):
		{
			pErrorAbortTx = &bCAN1ErrorAbortTx;
			poN_ErrorsAndErrorStatuses = &goN_CAN1ErrorsAndErrorStatuses;
		}

#   endif // of (1 == MX_FDCAN1)

#   if (1 == MX_FDCAN2)

		case (uint32_t)(FDCAN2):
		{
			pErrorAbortTx = &bCAN2ErrorAbortTx;
			poN_ErrorsAndErrorStatuses = &goN_CAN1ErrorsAndErrorStatuses;
		}

#   endif // of (1 == MX_FDCAN2)
	}

	nStatus.hs = HAL_ERROR;

	if ((1 == u32NumberOfMessagesToAddToTxFIFO) && (false == (*pErrorAbortTx)))
	{
		u32FDCAN_IR_Flags = CRC_Evans_CheckTxFifoLevel(hfdcan, &u32FreeLevel, pErrorAbortTx, poN_ErrorsAndErrorStatuses);
		if (0 == u32FDCAN_IR_Flags)
		{
			nStatus.hs = HAL_FDCAN_AddMessageToTxFifoQ(hfdcan, pTxHeader, pTxData);
		}
	}
	else if ((1 < u32NumberOfMessagesToAddToTxFIFO) && (false == (*pErrorAbortTx)))
	{
		uint32_t u32CurrentPutIndex = 0;

		uint32_t u32CollatedPutIndexes = 0;

		uint32_t u32TotalMessagesAddedToFIFO = 0;

		do
		{
			if (hfdcan->State == HAL_FDCAN_STATE_BUSY)
			{
				FDCAN_TxHeaderTypeDef* pThisTxHeader = pTxHeader;
				uint32_t u32MessagesToCheck = u32NumberOfMessagesToAddToTxFIFO;

				while ((0 != u32MessagesToCheck) && (false == (*pErrorAbortTx)))
				{
					/* Check function parameters */
					assert_param(IS_FDCAN_ID_TYPE(pThisTxHeader->IdType));
					if (pThisTxHeader->IdType == FDCAN_STANDARD_ID)
					{
						assert_param(IS_FDCAN_MAX_VALUE(pThisTxHeader->Identifier, 0x7FFU));
					}
					else /* pThisTxHeader->IdType == FDCAN_EXTENDED_ID */
					{
						assert_param(IS_FDCAN_MAX_VALUE(pThisTxHeader->Identifier, 0x1FFFFFFFU));
					}
					assert_param(IS_FDCAN_FRAME_TYPE(pThisTxHeader->TxFrameType));
					assert_param(IS_FDCAN_DLC(pThisTxHeader->DataLength));
					assert_param(IS_FDCAN_ESI(pThisTxHeader->ErrorStateIndicator));
					assert_param(IS_FDCAN_BRS(pThisTxHeader->BitRateSwitch));
					assert_param(IS_FDCAN_FDF(pThisTxHeader->FDFormat));
					assert_param(IS_FDCAN_EFC(pThisTxHeader->TxEventFifoControl));
					assert_param(IS_FDCAN_MAX_VALUE(pThisTxHeader->MessageMarker, 0xFFU));

					pThisTxHeader++;
					if (true == (*pErrorAbortTx))
					{
						break;
					}
					u32MessagesToCheck--;
				}
				if (0 < u32MessagesToCheck)
				{
					break;
				}

				// Resetting value stored with variable
				u32FreeLevel = 0;

				while ((0 != u32NumberOfMessagesToAddToTxFIFO) && (false == (*pErrorAbortTx)))
				{
					if(0 == u32FreeLevel)
					{
						u32FDCAN_IR_Flags = CRC_Evans_CheckTxFifoLevel(hfdcan, &u32FreeLevel, pErrorAbortTx, poN_ErrorsAndErrorStatuses);
						if ((0 != u32FDCAN_IR_Flags) || (0 == u32FreeLevel))
						{
							break;
						}
					}
					/* Check that the Tx FIFO/Queue has an allocated area into the RAM */
					if ((0 == (hfdcan->Instance->TXBC & FDCAN_TXBC_TFQS)) && (false == (*pErrorAbortTx)))
					{
//					if (0 == (hfdcan->Instance->IR & (FDCAN_ERROR_FLAGS)))
//					{
							/* Update error code */
							hfdcan->ErrorCode |= HAL_FDCAN_ERROR_PARAM;
							nStatus.hs = HAL_ERROR;
							assert_failed((uint8_t*)__FILE__, __LINE__);
//					}
//					else
//					{
//						u32FDCAN_IR_Flags = poN_ErorsAndErrorStatuses->u32CurrentFDCAN_IR_Value;
//					}
						break;
					}
					/* Check that the Tx FIFO/Queue is not full */
					if (((hfdcan->Instance->TXFQS & FDCAN_TXFQS_TFQF) != 0U) && (false == (*pErrorAbortTx)))
					{
						/* Update error code */
						hfdcan->ErrorCode |= HAL_FDCAN_ERROR_FIFO_FULL;
						nStatus.hs = HAL_ERROR;
						break;
					}
					else if (false == (*pErrorAbortTx))
					{
						const uint8_t DLCtoBytes[] = { 0, 1, 2, 3, 4, 5, 6, 7, 8, 12, 16, 20, 24, 32, 48, 64 };
						uint32_t TxElementW1;
						uint32_t TxElementW2;
						uint32_t* TxAddress;
						uint32_t ByteCounter;
						if (0 == u32TotalMessagesAddedToFIFO)
						{
							/* Retrieve the Tx FIFO PutIndex */
							u32CurrentPutIndex = ((hfdcan->Instance->TXFQS & FDCAN_TXFQS_TFQPI) >> FDCAN_TXFQS_TFQPI_Pos);
						}
						else
						{
							++u32CurrentPutIndex;
							if (hfdcan->Init.TxFifoQueueElmtsNbr <= u32CurrentPutIndex) // u32CollatedPutIndexes)
							{
								u32CurrentPutIndex = 0;	//u32CollatedPutIndexes = 0;
							}
						}
						/* Add the message to the Tx FIFO/Queue */
						// Function FDCAN_CopyMessageToRAM(hfdcan, pTxHeader, pTxData, u32CurrentPutIndex) is of type static hence copyingits code below:
						{
							/* Build first word of Tx header element */
							if (pTxHeader->IdType == FDCAN_STANDARD_ID)
							{
								TxElementW1 = (pTxHeader->ErrorStateIndicator |
											FDCAN_STANDARD_ID |
											pTxHeader->TxFrameType |
											(pTxHeader->Identifier << 18));
							}
							else /* pTxHeader->IdType == FDCAN_EXTENDED_ID */
							{
								TxElementW1 = (pTxHeader->ErrorStateIndicator |
											FDCAN_EXTENDED_ID |
											pTxHeader->TxFrameType |
											pTxHeader->Identifier);
							}

							/* Build second word of Tx header element */
							TxElementW2 = ((pTxHeader->MessageMarker << 24) |
										pTxHeader->TxEventFifoControl |
										pTxHeader->FDFormat |
										pTxHeader->BitRateSwitch |
										pTxHeader->DataLength);

							/* Calculate Tx element address */
							TxAddress = (uint32_t*)(hfdcan->msgRam.TxBufferSA + (u32CurrentPutIndex * hfdcan->Init.TxElmtSize * 4U));

							/* Write Tx element header to the message RAM */
							*TxAddress = TxElementW1;
							TxAddress++;
							*TxAddress = TxElementW2;
							TxAddress++;

							/* Write Tx payload to the message RAM */
							for (ByteCounter = 0; ByteCounter < DLCtoBytes[pTxHeader->DataLength >> 16]; ByteCounter += 4U)
							{
								*TxAddress = (((uint32_t)pTxData[ByteCounter + 3U] << 24) |
											((uint32_t)pTxData[ByteCounter + 2U] << 16) |
											((uint32_t)pTxData[ByteCounter + 1U] << 8) |
											(uint32_t)pTxData[ByteCounter]);
								TxAddress++;
							}
// #DRA: moved down:						pTxData += DLCtoBytes[pTxHeader->DataLength >> 16];
						}

						uint32_t u32BitPosition = ((uint32_t)1 << u32CurrentPutIndex);

// Check FDCAN Tx buffer request pending register for transmission pending for selected FIFO.
// In Reference Manual of STM32H753, under FDCAN_TXFQS register details, it is informed that:
// The Tx FIFO/queue status is related to the pending Tx requests listed in register
// FDCAN_TXBRP. Therefore the effect of add/cancellation requests may be delayed due to a
// running Tx scan (FDCAN_TXBRP not yet updated)
// Hence, I feel we can safely use FDCAN_TXBRP to know if a FIFO is available for write.
						//ValueTXBRP = hfdcan->Instance->TXBRP;
						//if ((ValueTXBRP & u32BitPosition) && (false == (*pErrorAbortTx)))
						//{
						//	assert_failed((uint8_t*)__FILE__, __LINE__);
						//}
						//else if (true == (*pErrorAbortTx))
						//{
						//	u32FDCAN_IR_Flags = poN_ErrorsAndErrorStatuses->u32CurrentFDCAN_IR_Value;
						//	nStatus.cs = CANErrorOrErrorStatusTriggered;
						//	return nStatus;
						//	break;
						//}

						/* Collate corresponding transmission request */
						u32CollatedPutIndexes |= u32BitPosition;

						/* Store the Latest Tx FIFO/Queue Request Buffer Index */
						hfdcan->LatestTxFifoQRequest = u32BitPosition;

						++u32TotalMessagesAddedToFIFO;
						--u32NumberOfMessagesToAddToTxFIFO;

						if (true == (*pErrorAbortTx))
						{
							break;
						}

						if (((u32TotalMessagesAddedToFIFO == u32FreeLevel) || (0 == u32NumberOfMessagesToAddToTxFIFO)) && (false == (*pErrorAbortTx)))
						{
							/* Activate the collated transmission requests */
							hfdcan->Instance->TXBAR = u32CollatedPutIndexes;

							if (0 == u32NumberOfMessagesToAddToTxFIFO)
							{
								nStatus.hs = HAL_OK;
								break;
							}
							else
							{
								u32TotalMessagesAddedToFIFO = 0;
								u32CollatedPutIndexes = 0;
								u32FreeLevel = 0;
							}
						}
						if (0 != u32NumberOfMessagesToAddToTxFIFO)
						{
							pTxData += DLCtoBytes[pTxHeader->DataLength >> 16];
							// Point to next valid Header which is to be transmitted.
							pTxHeader++;
						}
					}
				}
			}
			else
			{
				/* Update error code */
				hfdcan->ErrorCode |= HAL_FDCAN_ERROR_NOT_STARTED;
				nStatus.hs = HAL_ERROR;
				break;
			}
		} while (0);
	}
	if ((true == (*pErrorAbortTx)) || u32FDCAN_IR_Flags)
	{
		(*pErrorAbortTx) = true;
		hfdcan->ErrorCode |= u32FDCAN_IR_Flags;
		nStatus.cs = CANErrorOrErrorStatusTriggered;
	}
	return nStatus;
}

#  endif // of defined(dAddMultipleTxCANMessagesToFIFO)


//
//- - - - - - - - rvCRC_Evans_FDCAN_ConfigFiler - - - - - - -
//
void rvCRC_Evans_FDCAN_ConfigFiler(
	uint8_t							*	const pu8MaxExtendedCANFilters,
	uint8_t							* const pu8MaxStandardCANFilters,
	FDCAN_HandleTypeDef	* const oThisFDCANHandleTypeDef        /*!< Register base address     */
)
{
	FDCAN_FilterTypeDef * pgNoClassicCANReceiveMessageFilters = NULL;
	uint32_t u32MaxCount = *(pu8MaxExtendedCANFilters) + *(pu8MaxStandardCANFilters);

	// Converting 32 bit address to a 32 bit value and checking what must be executed.
	// Switch cannot act upon addresses, it can however act on integer type values
	switch((uint32_t)oThisFDCANHandleTypeDef->Instance)
	{
		default:
		{
			assert_failed((uint8_t *)__FILE__, __LINE__);
			break;
		}

#  if (1 == MX_FDCAN1)

		case (uint32_t)(FDCAN1):
		{
			if(u32MaxCount > dUsedCAN1TxFIFOElmtsNbr)
			{
				dOutputConstantErrorMessage("\nRequired RX FIFO for CAN 1 is greater than usable RX FIFOs!");
				dLEDShowError(dNoMoreCAN1_RX_FIFO_Available);
			}
			pgNoClassicCANReceiveMessageFilters = gNoClassicCAN1ReceiveMessageFilters;
			break;
		}

#  endif // of (1 == MX_FDCAN1)

#  if (1 == MX_FDCAN2)

		case (uint32_t)(FDCAN2):
		{
			if(u32MaxCount > dUsedCAN2TxFIFOElmtsNbr)
			{
				dOutputConstantErrorMessage("\nRequired RX FIFO for CAN 2 is greater than usable RX FIFOs!");
				dLEDShowError(dNoMoreCAN2_RX_FIFO_Available);
			}
			pgNoClassicCANReceiveMessageFilters = gNoClassicCAN2ReceiveMessageFilters;
			break;
		}

#  endif // of (1 == MX_FDCAN2)
	}

	assert_param(NULL != pgNoClassicCANReceiveMessageFilters);

	uint32_t u32Count = 0;
	while(u32Count < u32MaxCount)
	{
		pgNoClassicCANReceiveMessageFilters->FilterIndex = u32Count;
		if(HAL_OK != HAL_FDCAN_ConfigFilter((FDCAN_HandleTypeDef *)oThisFDCANHandleTypeDef, (FDCAN_FilterTypeDef *)pgNoClassicCANReceiveMessageFilters))
		{
#  if (1 == MX_FDCAN1)

			if(FDCAN1 == oThisFDCANHandleTypeDef->Instance)
			{
				dLEDShowError(dFDCAN1FilterConfigFail);
			}

#  endif // of (1 == MX_FDCAN1)

#  if (1 == MX_FDCAN2)

			if(FDCAN2 == oThisFDCANHandleTypeDef->Instance)
			{
				dLEDShowError(dFDCAN2FilterConfigFail);
			}

#  endif // of (1 == MX_FDCAN2)

			assert_failed((uint8_t *)__FILE__, __LINE__);
		}
		++pgNoClassicCANReceiveMessageFilters;
		++u32Count;
	}
}

# endif // of (1 == MX_FDCAN1) || (1 == MX_FDCAN2)


