// #DRA:
//
// NOTES:
//
// The FDCAN calculates the Tx FIFO free level FDCAN_TXFQS.TFFL as difference between get and
// put index. New transmit messages have to be written to the Tx FIFO starting with the Tx
// buffer referenced by the put index FDCAN_TXFQS.TFQPI.
//
// FDCAN Tx FIFO/queue status register (FDCAN_TXFQS)
// The Tx FIFO/queue status is related to the pending Tx requests listed in register
// FDCAN_TXBRP. Therefore the effect of add/cancellation requests may be delayed due to a
// running Tx scan (FDCAN_TXBRP not yet updated).
//
// IMPORTANT:
//
// 1. When a single message is added to the Tx FIFO, the transmission is requested by writing a
// 1 to the FDCAN_TXBAR bit related to the Tx buffer referenced by the Tx FIFO put index.
//
// 2. When multiple (n) messages are added to the Tx FIFO, they are written to n consecutive Tx
// buffers starting with the put index. The transmissions are then requested via
// FDCAN_TXBAR. The put index is then cyclically incremented by n. The number of
// requested Tx buffers should not exceed the number of free Tx buffers as indicated by the Tx
// FIFO free level.
//

//
//- - - - - - - - CRC_Evans_CheckTxFifoLevel - - - - - - -
//
uint32_t CRC_Evans_CheckTxFifoLevel(FDCAN_HandleTypeDef* hfdcan, uint32_t * pu32FreeLevel, bool * pErrorAbortTx, toN_ErrorsAndErrorStatuses * poN_ErrorsAndErrorStatuses)
{
	int iRetries = 0;
	uint32_t u32FDCAN_IR_Flags = 0;
	/* Get number of consecutive free Tx FIFO elements starting from Tx FIFO GetIndex. */
	/* Free Level is the number of FIFOs that are available to receive the Tx CAN Frames. */
	while (0 == ((*pu32FreeLevel) = HAL_FDCAN_GetTxFifoFreeLevel(hfdcan)))
	{
		if ((dCANRetryCounts == iRetries) && (false == (*pErrorAbortTx)))
		{
			assert_failed((uint8_t*)__FILE__, __LINE__);
			break;
		}
		else if ((false == (*pErrorAbortTx)) && (0 != (hfdcan->Instance->IR & (FDCAN_ERROR_FLAGS))))
		{
			u32FDCAN_IR_Flags = poN_ErrorsAndErrorStatuses->u32CurrentFDCAN_IR_Value | (hfdcan->Instance->IR & (FDCAN_ERROR_FLAGS));
			break;
		}
		else if (true == (*pErrorAbortTx))
		{
			u32FDCAN_IR_Flags = poN_ErrorsAndErrorStatuses->u32CurrentFDCAN_IR_Value;
			break;
		}
		else
		{
			HAL_Delay(1);
		}
		iRetries++;
	}
	return u32FDCAN_IR_Flags;
}

