//
//- - - - - - - - rvCAN1_Initialize - - - - - - -
//
void rvCAN1_Initialize(void)
{
#  if (1==_DRA_USE_FDCAN1_AS_FDCAN_)
// Transmit Delay Compensation Enabled.
// Refer to section "55.3.1 Operating modes" part "Transceiver delay compensation"
// for details
	HAL_FDCAN_EnableTxDelayCompensation(&hfdcan1);

// NOTES:
// FDCAN_PSR.TDCV shows the actual transmitter delay compensation value, it is cleared
// when FDCAN_CCCR.INIT is set and is updated at each transmission of an FD frame while
// FDCAN_DBTP.TDC is set.
// The following boundary conditions have to be considered for the transmitter delay
// compensation implemented in the FDCAN:
//  The sum of the measured delay from m_ttcan_tx to m_ttcan_rx and the configured
// transmitter delay compensation offset FDCAN_TDCR.TDCO has to be less than six bit
// times in the data phase.
//  The sum of the measured delay from m_ttcan_tx to m_ttcan_rx and the configured
// transmitter delay compensation offset FDCAN_TDCR.TDCO has to be less or equal
// 127 mtq. In case this sum exceeds 127 mtq, the maximum value (127 mtq) is used for
// transmitter delay compensation.
//  The data phase ends at the sample point of the CRC delimiter, that stops checking
// received bits at the SSPs
#  endif

///** @defgroup FDCAN_Tx_Interrupts FDCAN Tx Interrupts
//#DRA: Added to Interrupt requests: #define FDCAN_IT_TX_COMPLETE           FDCAN_IE_TCE   /*!< Transmission Completed                                */
//#define FDCAN_IT_TX_ABORT_COMPLETE     FDCAN_IE_TCFE  /*!< Transmission Cancellation Finished                    */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_TX_FIFO_EMPTY         FDCAN_IE_TFEE  /*!< Tx FIFO Empty                                         */

///** @defgroup FDCAN_Counter_Interrupts FDCAN Counter Interrupts
//#define FDCAN_IT_TIMESTAMP_WRAPAROUND  FDCAN_IE_TSWE  /*!< Timestamp counter wrapped around                      */
//#define FDCAN_IT_TIMEOUT_OCCURRED      FDCAN_IE_TOOE  /*!< Timeout reached                                       */

///** @defgroup FDCAN_Clock_Calibration_Interrupts Clock Calibration Interrupts
//#define FDCAN_IT_CALIB_STATE_CHANGED  (FDCANCCU_IE_CSCE << 30) /*!< Clock calibration state changed           */
//#define FDCAN_IT_CALIB_WATCHDOG_EVENT (FDCANCCU_IE_CWEE << 30) /*!< Clock calibration watchdog event occurred */

///** @defgroup FDCAN_Error_Interrupts FDCAN Error Interrupts
//#DRA: Added to Interrupt requests: #define FDCAN_IT_RAM_ACCESS_FAILURE      FDCAN_IE_MRAFE /*!< Message RAM access failure occurred              */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_ERROR_LOGGING_OVERFLOW  FDCAN_IE_ELOE  /*!< Overflow of FDCAN Error Logging Counter occurred */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_RAM_WATCHDOG            FDCAN_IE_WDIE  /*!< Message RAM Watchdog event due to missing READY  */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_ARB_PROTOCOL_ERROR      FDCAN_IE_PEAE  /*!< Protocol error in arbitration phase detected     */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_DATA_PROTOCOL_ERROR     FDCAN_IE_PEDE  /*!< Protocol error in data phase detected            */
//#DRA: Added to Interrupt requests: #define FDCAN_IT_RESERVED_ADDRESS_ACCESS FDCAN_IE_ARAE  /*!< Access to reserved address occurred              */

//HAL_StatusTypeDef HAL_FDCAN_ConfigRamWatchdog(FDCAN_HandleTypeDef *hfdcan, uint32_t CounterStartValue);
//HAL_StatusTypeDef HAL_FDCAN_ConfigExtendedIdMask(FDCAN_HandleTypeDef *hfdcan, uint32_t Mask);
//HAL_StatusTypeDef HAL_FDCAN_ConfigTxDelayCompensation(FDCAN_HandleTypeDef *hfdcan, uint32_t TdcOffset, uint32_t TdcFilter);
//HAL_StatusTypeDef HAL_FDCAN_ConfigInterruptLines(FDCAN_HandleTypeDef *hfdcan, uint32_t ITList, uint32_t InterruptLine);

/* Activate various FDCAN_Error_Interrupts notifications. */
	HAL_FDCAN_ActivateNotification( &hfdcan1
																,	0
//															| FDCAN_IT_RAM_ACCESS_FAILURE				/*!< Message RAM access failure occurred              */
//															| FDCAN_IT_ERROR_LOGGING_OVERFLOW		/*!< Overflow of FDCAN Error Logging Counter occurred */
//															| FDCAN_IT_RAM_WATCHDOG							/*!< Message RAM Watchdog event due to missing READY  */
//															| FDCAN_IT_RESERVED_ADDRESS_ACCESS	/*!< Access to reserved address occurred              */
																, 0);

// NOTES:
//
// The Bus_Off recovery sequence (see CAN Specification Rev. 2.0 or ISO11898-1) cannot be
// shortened by setting or resetting FDCAN_CCCR.INIT. If the device goes Bus_Off, it will set
// FDCAN_CCCR.INIT of its own, stopping all bus activities. Once FDCAN_CCCR.INIT has
// been cleared by the CPU, the device will then wait for 129 occurrences of bus Idle (129 × 11
// consecutive recessive bits) before resuming normal operation. At the end of the Bus_Off
// recovery sequence, the error management counters will be reset. During the waiting time
// after the reset of FDCAN_CCCR.INIT, each time a sequence of 11 recessive bits has been
// monitored, a Bit0 error code is written to FDCAN_PSR.LEC, enabling the CPU to readily
// check up whether the CAN bus is stuck at dominant or continuously disturbed and to
// monitor the Bus_Off recovery sequence. FDCAN_ECR.REC is used to count these
// sequences.

/* Activate various FDCAN_Error_Status_Interrupts notifications. */
	HAL_FDCAN_ActivateNotification( &hfdcan1
																,	0
																| FDCAN_IT_ERROR_WARNING	/*!< Error_Warning status changed */
// #DRA: These interrupts are Polled for, when Error Warning is triggered.
//															| FDCAN_IT_BUS_OFF       /*!< Bus_Off status changed       */
																| FDCAN_IT_ERROR_PASSIVE /*!< Error_Passive status changed */
//															|	FDCAN_IT_ARB_PROTOCOL_ERROR		/*!< Protocol error in arbitration phase detected     */
//															| FDCAN_IT_DATA_PROTOCOL_ERROR	/*!< Protocol error in data phase detected            */
																, 0);

// NOTES:
//
// To support Tx event handling the FDCAN has implemented a Tx event FIFO. After the
// FDCAN has transmitted a message on the CAN bus, message ID and timestamp are stored
// in a Tx event FIFO element. To link a Tx event to a Tx event FIFO element, the message
// marker from the transmitted Tx buffer is copied into the Tx event FIFO element.
// The Tx event FIFO can be configured to a maximum of 32 elements. The Tx event FIFO
// element is described in Tx FIFO. Depending on the configuration of the element size
// (FDCAN_TXESC), between two and sixteen 32-bit words (Tn = 3 ..17) are used for storage
// of a CAN message data field.
//
// When a Tx event FIFO full condition is signaled by FDCAN_IR.TEFF, no further elements
// are written to the Tx event FIFO until at least one element has been read out and the Tx
// event FIFO get index has been incremented. In case a Tx event occurs while the Tx event
// FIFO is full, this event is discarded and interrupt flag FDCAN_IR.TEFL is set.
//
// To avoid a Tx event FIFO overflow, the Tx event FIFO watermark can be used. When the Tx
// event FIFO fill level reaches the Tx event FIFO watermark configured by
// FDCAN_TXEFC.EFWM, interrupt flag FDCAN_IR.TEFW is set.
// When reading from the Tx event FIFO, two times the Tx event FIFO get index
// FDCAN_TXEFS.EFGI has to be added to the Tx event FIFO start address
// FDCAN_TXEFC.EFSA.

// IMPORTANT NOTE:
//
// NONE OF THE BELOW TX INTERRUPTS are used
//
// FDCAN_IT_TX_EVT_FIFO_FULL			/*!< Tx Event FIFO full                         */
// FDCAN_IT_TX_EVT_FIFO_WATERMARK	/*!< Tx Event FIFO fill level reached watermark */
// FDCAN_IT_TX_EVT_FIFO_NEW_DATA	/*!< Tx Handler wrote Tx Event FIFO element     */
// FDCAN_IT_TX_FIFO_EMPTY					/*!< Tx FIFO Empty                              */
//
// This is because when sending out multiple CAN MEssages, it takes a while for the interrupts to Trigger.
// The TX FIFO alreadys gets full before any interrupt gets triggered, and hence at least one CAN TX
// message gets lost.
//
// It is rather beneficial to first check for TX FIFO Full (related register) before starting to add
// any data, and then use HAL_FDCAN_GetTxFifoFreeLevel() to know how many more buffers are available.

/* Activate various FDCAN_Tx_Event_Fifo_Interrupt notifications */
	HAL_FDCAN_ActivateNotification(&hfdcan1
																, 0
																| FDCAN_IT_TX_FIFO_EMPTY	/*!< Tx FIFO Empty                */
//#   if (0 < dUseCAN1TxEventsNbr)
//															| FDCAN_IT_TX_EVT_FIFO_ELT_LOST		/*!< Tx Event FIFO element lost                 */
//															| FDCAN_IT_TX_EVT_FIFO_NEW_DATA
//#   endif // of (0 < dUseCAN1TxEventsNbr)
//															| FDCAN_IT_TX_EVT_FIFO_FULL
//															| FDCAN_IT_TX_COMPLETE						/*!< Transmission Completed                     */
															, 0); //~((-1UL) << dUseCAN1TxEventsNbr));

/* Configure global filter to reject all non-matching frames */
	if(HAL_OK != HAL_FDCAN_ConfigGlobalFilter(&hfdcan1, dCAN1NonMatchingStd, dCAN1NonMatchingExt, dCAN1RejectRemoteStd, dCAN1RejectRemoteExt))
	{
		dLEDShowError(dFDCAN1GlobalFilterConfigFail);
		assert_failed((uint8_t *)__FILE__, __LINE__);
	}

/* Configure Rx FIFO 0 Blocking or Overwrite. */
	HAL_FDCAN_ConfigRxFifoOverwrite(&hfdcan1
																, FDCAN_RX_FIFO0
#   if defined(dCAN1RxFIFO0InBlockingMode)
																,	FDCAN_RX_FIFO_BLOCKING
#   elif defined(dCAN1RxFIFO0InOverwriteMode)
																, FDCAN_RX_FIFO_OVERWRITE
#   endif // of defined(dCAN1RxFIFO0InBlockingMode)
																);
#  endif // of ( ( dFIFO0AcceptsUnknownCANMessages | dFIFO0ReceivesFilteredCANMessages) & ( dUsedCAN1RxFIFOConfiguration ) )

/* Activate various FDCAN_Rx_Fifo0_Interrupts notifications */
	if(HAL_OK !=
					HAL_FDCAN_ActivateNotification( &hfdcan1
																				,	0
																				| FDCAN_IT_RX_FIFO0_FULL         /*!< Rx FIFO 0 full                         */
																				| FDCAN_IT_RX_FIFO0_NEW_MESSAGE  /*!< New message written to Rx FIFO 0       */
#   if defined(dCAN1RxFIFO0InBlockingMode)
																				| FDCAN_IT_RX_FIFO0_MESSAGE_LOST /*!< Rx FIFO 0 message lost                 */
#   endif // of defined(dCAN1RxFIFO0InBlockingMode)
#   if (dCAN1RxFIFOElmtsLeftToFull < dUsedCAN1RxFIFO0ElmtsNbr)
																				| FDCAN_IT_RX_FIFO0_WATERMARK    /*!< Rx FIFO 0 fill level reached watermark */
#   endif // of (dCAN1RxFIFOElmtsLeftToFull < dUsedCAN1RxFIFO0ElmtsNbr)
																			, 0)
			)
	{
		dLEDShowError(dFDCAN1ActivateNotificationFail);
		assert_failed((uint8_t *)__FILE__, __LINE__);
	}

/* Configure Rx FIFO 1 Blocking or Overwrite. */
	HAL_FDCAN_ConfigRxFifoOverwrite(&hfdcan1
																, FDCAN_RX_FIFO1
#   if defined(dCAN1RxFIFO1InBlockingMode)
																,	FDCAN_RX_FIFO_BLOCKING
#   elif defined(dCAN1RxFIFO1InOverwriteMode)
																, FDCAN_RX_FIFO_OVERWRITE
#   endif // of defined(dCAN1RxFIFO1InBlockingMode)
																);
#  endif // of ( ( dFIFO1AcceptsUnknownCANMessages | dFIFO1ReceivesFilteredCANMessages) & ( dUsedCAN1RxFIFOConfiguration ) )

/* Activate various DCAN_RX_FIFO1_Interrupts notifications */
	if(HAL_OK !=
				HAL_FDCAN_ActivateNotification(	&hfdcan1
																			,	0
																				| FDCAN_IT_RX_FIFO1_FULL         /*!< Rx FIFO 0 full                         */
																				| FDCAN_IT_RX_FIFO1_NEW_MESSAGE  /*!< New message written to Rx FIFO 1       */
#   if defined(dRxFIFO1InBlockingMode)
																				| FDCAN_IT_RX_FIFO1_MESSAGE_LOST /*!< Rx FIFO 0 message lost                 */
#   endif // of dRxFIFO0InBlockingMode
#   if (dCAN1RxFIFOElmtsLeftToFull < dUsedCAN1RxFIFO1ElmtsNbr)
																				| FDCAN_IT_RX_FIFO1_WATERMARK    /*!< Rx FIFO 1 fill level reached watermark */
#   endif // of (dCAN1RxFIFOElmtsLeftToFull < dUsedCAN1RxFIFO1ElmtsNbr)
																			, 0)
		)
	{
		dLEDShowError(dFDCAN1ActivateNotificationFail);
		assert_failed((uint8_t *)__FILE__, __LINE__);
	}

if(HAL_OK != HAL_FDCAN_Start(&hfdcan1))
	{
		dLEDShowError(dFDCAN1ModuleStartFail);
		assert_failed((uint8_t *)__FILE__, __LINE__);
	}
}

