  }
  if (HAL_OK != HAL_DFSDM_FilterRegularStart_DMA(&DfsdmLeftFilterHandle, LeftRecBuff, 2048))
  {
    printf("HAL_DFSDM_FilterRegularStart_DMA failed!! DfsdmLeftFilterHandle\r\n");
    return (-1);
  }

